#include<bits/stdc++.h>
using namespace std;
int n,m;
vector<int> mp[100010];
int in[100010];
int cnt=0;
bool flag[100010];
vector<int> dcc[100010];
int dfn[100010],low[100010],dcccnt,dfncnt;
stack<int> s;
void tarjan(int x)
{
    int soncnt=0;
    dfn[x]=low[x]=++dfncnt;
    s.push(x);
    for(int v:mp[x])
    {
        if(!dfn[v])
        {
            tarjan(v);
            low[x]=min(low[x],low[v]);
            if(dfn[x]<=low[v])
            {
                soncnt++;
                dcccnt++;
                if(x!=1||soncnt>1)
                {
                    flag[x]=1;
                }
                int top=0;
                dcc[dcccnt].push_back(x);
                do
                {
                    top=s.top();
                    s.pop();
                    dcc[dcccnt].push_back(top);
                }while(top!=v);
            }
        }
        else
        {
            low[x]=min(low[x],dfn[v]);
        }
    }
}
int main()
{
    n=1000;
    int c=0;
    while(scanf("%d",&m)==1&&m)
    {
        while(!s.empty())
        {
            s.pop();
        }
        for(int i=1;i<=n;i++)
        {
            mp[i].clear();
        }
        for(int i=1;i<=dcccnt;i++)
        {
            dcc[i].clear();
        }
        dcccnt=dfncnt=0;
        memset(flag,0,sizeof(flag));
        memset(low,0,sizeof(low));
        memset(dfn,0,sizeof(dfn));
        int ans1=0;
        long long ans2=1;
        for(int i=1;i<=m;i++)
        {
            int u,v;
            scanf("%d%d",&u,&v);
            mp[u].push_back(v);
            mp[v].push_back(u);
        }
        tarjan(1);
        for(int i=1;i<=dcccnt;i++)
        {
            int v1=dcc[i].size(),v2=0;
            for(int j:dcc[i])
            {
                v2+=flag[j];
            }
            if(v2==1)
            {
                ans1++;
                ans2*=v1-1;
            }
            if(v2==0)
            {
                ans1+=2;
                ans2*=1ll*v1*(v1-1)/2;
            }
        }
        printf("Case %d: %d %lld\n",++cnt,ans1,ans2);
    }
    return 0;
}
